const entry = $input.first().json;

let phone = '';
let name = '';
let messageText = '';
let messageId = '';
let waId = '';

try {
  const changes = entry.entry?.[0]?.changes?.[0];
  const value = changes?.value;
  const message = value?.messages?.[0];
  const contact = value?.contacts?.[0];

  phone = message?.from || '';
  messageText = message?.text?.body || '';
  messageId = message?.id || '';
  waId = contact?.wa_id || phone;
  name = contact?.profile?.name || 'Unknown';
} catch(e) {
  phone = entry.from || '';
  messageText = entry.text?.body || entry.body || '';
  messageId = entry.id || '';
  waId = phone;
  name = 'Unknown';
}

return [{
  json: {
    phone,
    name,
    messageText,
    messageId,
    waId,
    timestamp: new Date().toISOString()
  }
}];

const items = $input.all();
if (!items || items.length === 0 || !items[0].json || Object.keys(items[0].json).length === 0) {
  return [{ json: { status: 'new_lead', message: 'This is a new lead with no previous history.' } }];
}
const lead = items[0].json;
return [{ json: { status: 'returning_lead', lead, message: `Returning lead found: ${lead.Name || 'Unknown'}, Email: ${lead.Email || 'N/A'}, Last Appointment: ${lead['Last Appointment'] || 'N/A'}` } }];

const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { result: 'No specific information found in the knowledge base for this query. Please contact us directly for more details.' } }];
}
const results = items.map(i => i.json).filter(r => Object.keys(r).length > 0);
if (results.length === 0) {
  return [{ json: { result: 'No specific information found. Please contact us directly.' } }];
}
const combined = results.map(r => `Topic: ${r.Topic || 'General'}\nAnswer: ${r.Answer || r.Content || JSON.stringify(r)}`).join('\n\n');
return [{ json: { result: combined } }];
